challenges.test_code:
assert parse_query_string('http://example.com/search?q=python&page=2') == {'q': 'python', 'page': '2'}
assert parse_query_string('http://example.com/') == {}
assert parse_query_string('http://example.com/path') == {}
result = parse_query_string('http://example.com/?name=alice&age=30&city=NYC')
assert result == {'name': 'alice', 'age': '30', 'city': 'NYC'}
result2 = parse_query_string('http://example.com/?key=first&key=second')
assert result2 == {'key': 'second'}
assert parse_query_string('http://example.com/?empty=') == {'empty': ''}
